texttool_globals_dialog_2_buttons___installation_final_state_button_bcall = TextObject(bs_BA="Prebaciti na online poziv zbog kvara", cs_CZ="Přepnout na havarijní volání online", da_DK="Skift til onlinevejhjælpsopkald", de_DE="Zum Online-Pannenruf wechseln", el_GR="Προς την online κλήση για βλάβη", en_GB="Switch to online roadside assistance", es_ES="A llamada de asistencia online", fi_FI="Vaihda online-tiepalvelupuheluun", fr_FR="Accéder à appel dépannage en ligne", hr_HR="Na online poziv za pomoć na cesti", hu_HU="Átkapcs. Online műszaki segélyhív.ra", it_IT="Vai a chiamata soccorso strad. online", nl_NL="Naar online pechoproep overgaan", no_NO="Bytt til online veitjeneste", pl_PL="Przejdź do wezwania pomocy online", pt_PT="Mudar p. cham. de assistência online", ro_RO="Comutare la apelul de pană online", ru_RU="Перекл. на онл.-вызов при аварии", sk_SK="Zmeniť na Online volanie pri poruche", sl_SI="Preklop na spletni klic ob okvari", sr_RS="Prebaciti na onlajn poziv zbog kvara", sv_SE="Växla till servicesamtal online", tr_TR="Çevrimiçi arıza çağrısına geç", uk_UA="Переключ. до авар. виклику онлайн")
texttool_globals_dialog_message___close_wizard_confirmation_dialog_text_after_confirmation = TextObject(bs_BA="Želite li zaista napustiti postupak? Aktualizacija će se izvršiti prema planu.", cs_CZ="Chcete skutečně postup opustit? Update se provede podle plánu.", da_DK="Vil du virkelig forlade processen? Opdateringen gennemføres som planlagt.", de_DE="Möchtest du den Vorgang wirklich verlassen?\nDas Update wird wie geplant durchgeführt.", el_GR="Θέλετε σίγουρα να βγείτε από τη διαδικασία; Η αναβάθμιση θα πραγματοποιηθεί,\nόπως προγραμματίστηκε.", en_GB="Do you really want to exit the process? The update will be performed as planned.", es_ES="¿Realmente desea abandonar el proceso? La actualización se ejecutará\nsegún lo previsto.", fi_FI="Haluatko varmasti poistua menettelystä? Päivitys suoritetaan suunnitellusti.", fr_FR="Souhaitez-vous vraiment quitter la procédure? La mise à jour sera réalisée\ncomme prévu.", hr_HR="Želite li uistinu napustiti postupak? Update će se provesti kako je planirano.", hu_HU="Biztosan ki szeretnél lépni a folyamatból? A frissítés a tervek szerint fog\nmegvalósulni.", it_IT="Abbandonare il processo? L'update verrà eseguito come previsto nella\npianificazione.", nl_NL="Wil je het proces echt verlaten? De update wordt uitgevoerd zoals gepland.", no_NO="Er du sikker på at du vil forlate prosessen? Oppdateringen utføres som planlagt.", pl_PL="Czy na pewno chcesz wyjść z tej operacji? Aktualizacja jest realizowana\nzgodnie z planem.", pt_PT="Queres mesmo sair do procedimento? A atualização será realizada tal\ncomo planeado.", ro_RO="Doriţi într-adevăr să părăsiţi procesul? Actualizarea va fi executată conform\nplanificării.", ru_RU="Вы действительно хотите выйти? Обновление будет выполнено в соответствии\nс планом.", sk_SK="Skutočne chcete ukončiť proces? Aktualizácia sa vykoná podľa plánu.", sl_SI="Ali res želite zapustiti postopek? Posodobitev se bo izvedla, kot je bilo načrtovano.", sr_RS="Da li želite da napustite postupak? Ažuriranje će se izvršiti prema planu.", sv_SE="Vill du verkligen lämna processen? Uppdateringen genomförs som planerat.", tr_TR="Gerçekten işlemden çıkmak istiyor musun? Güncelleme planlandığı gibi yapılacaktır.", uk_UA="Ви дійсно хочете вийти? Оновлення буде виконано відповідно до плану.")
texttool_globals_dialog_message___close_wizard_confirmation_dialog_text_after_confirmation_with_timer = TextObject(bs_BA="Želite li zaista napustiti postupak? Aktualizacija će se, prema planu, izvršiti u\n%1 sati.", cs_CZ="Opravdu chcete proces ukončit? Aktualizace bude provedena podle plánu v\n%1 hodin.", da_DK="Vil du virkelig forlade processen? Opdateringen gennemføres som planlagt\nkl. %1.", de_DE="Möchtest du den Vorgang wirklich verlassen?\nDas Update wird wie geplant um %1 Uhr durchgeführt.", el_GR="Θέλετε σίγουρα να βγείτε από τη διαδικασία; Η αναβάθμιση θα εκτελεστεί, όπως έχει\nπρογραμματιστεί, στις %1 η ώρα.", en_GB="Do you really want to leave the process? The update will be performed at\n%1 as planned.", es_ES="¿Realmente desea abandonar el proceso? La actualización se ejecutará a las\n%1 según lo previsto.", fi_FI="Haluatko varmasti poistua menettelystä? Päivitys suoritetaan suunnitellusti klo\n%1.", fr_FR="Souhaitez-vous vraiment quitter la procédure? La mise à jour sera réalisée comme\nprévu à %1h.", hr_HR="Želite li postupak uistinu napustiti? Update će se provesti po planu u\n%1 h.", hu_HU="Biztosan ki szeretnél lépni a folyamatból? A frissítés a a tervezettnek megfelelően\n%1 órakor történik.", it_IT="Abbandonare il processo? L'update verrà eseguito alle %1 come\nprevisto.", nl_NL="Wil je het proces echt verlaten? De update wordt zoals gepland om\n%1 uur uitgevoerd.", no_NO="Er du sikker på at du vil forlate prosessen? Oppdateringen utføres kl.\n%1 som planlagt.", pl_PL="Czy na pewno chcesz wyjść z tej operacji? Aktualizacja zostanie przeprowadzona\nzgodnie z planem o godzinie %1.", pt_PT="Queres mesmo sair do procedimento? A atualização será realizada às\n%1 horas, tal como planeado.", ro_RO="Doriţi într-adevăr să părăsiţi procesul? Actualizarea va fi executată conform\nplanificării, la ora %1.", ru_RU="Вы действительно хотите завершить процесс? Обновление будет выполнено в\nсоответствии с планом в %1.", sk_SK="Skutočne chcete ukončiť proces? Aktualizácia sa vykoná podľa plánu o\n%1 hodine.", sl_SI="Ali res želite zapustiti postopek? Posodobitev se bo ob %1 izvedla,\nkot je bilo načrtovano.", sr_RS="Da li zaista želite napustiti postupak? Ažuriranje će biti izvršeno u skladu\nsa planom u %1 časova.", sv_SE="Vill du verkligen lämna proceduren? Uppdateringen utförs kl. %1\nsom planerat.", tr_TR="Gerçekten işlemden çıkmak istiyor musun? Güncelleme planlandığı gibi saat\n%1'de gerçekleştirilecek.", uk_UA="Ви дійсно хочете вийти? Оновлення буде виконано відповідно до плану о\n%1.")
texttool_globals_dialog_message___close_wizard_confirmation_dialog_text_before_confirmation = TextObject(bs_BA="Želite li zaista prekinuti postupak? Aktualizacija se neće izvršiti.", cs_CZ="Chcete skutečně postup přerušit? Update se neprovede.", da_DK="Vil du virkelig afbryde processen? Opdatering gennemføres ikke.", de_DE="Möchtest du den Vorgang wirklich abbrechen? Das Update wird nicht\ndurchgeführt.", el_GR="Θέλετε σίγουρα να διακόψετε τη διαδικασία; Η αναβάθμιση δεν θα πραγματοποιηθεί.", en_GB="Do you really want to cancel the process? The update will not be performed.", es_ES="¿Realmente desea cancelar el proceso? La actualización no se ejecutará.", fi_FI="Haluatko varmasti keskeyttää menettelyn? Päivitystä ei suoriteta.", fr_FR="Souhaitez-vous vraiment annuler la procédure? La mise à jour ne sera pas réalisée.", hr_HR="Želite li uistinu prekinuti postupak? Update se neće provesti.", hu_HU="Biztosan meg szeretnéd szakítani a folyamatot? A frissítés nem kerül\nvégrehajtásra.", it_IT="Interrompere il processo? L'update non verrà eseguito.", nl_NL="Wil je het proces echt annuleren? De update wordt niet uitgevoerd.", no_NO="Er du sikker på at du vil avbryte prosessen? Oppdateringen utføres ikke.", pl_PL="Czy na pewno chcesz anulować tę operację? Aktualizacja nie zostanie\nprzeprowadzona.", pt_PT="Queres mesmo cancelar o procedimento? A atualização não será realizada.", ro_RO="Doriţi într-adevăr să întrerupeţi procesul? Nu se va executa actualizarea.", ru_RU="Вы действительно хотите отменить процесс? Обновление не будет выполнено.", sk_SK="Skutočne chcete zrušiť proces? Aktualizácia sa nevykoná.", sl_SI="Ali res želite prekiniti postopek? Posodobitev ne bo izvedena.", sr_RS="Da li zaista želite da prekinete postupak? Ažuriranje se neće izvršiti.", sv_SE="Vill du verkligen avbryta processen. Uppdateringen genomförs inte.", tr_TR="Gerçekten işlemi iptal etmek istiyor musun? Güncelleme yapılmayacaktır.", uk_UA="Ви дійсно хочете скасувати процес? Оновлення не буде виконано.")
texttool_globals_dialog_message___no_updates_dialog = TextObject(bs_BA="Postupak je prekinut. Provjerite kasnije da li je raspoloživa aktualizacija\nsoftvera.", cs_CZ="Proces byl zrušen. Později zkontrolujte, zda je k dispozici aktualizace softwaru. ", da_DK="Handling blev afbrudt. Kontroller på et senere tidspunkt, om en\nsoftwareopdatering er tilgængelig.", de_DE="Der Vorgang wurde abgebrochen. Bitte prüfe zu einem späteren Zeitpunkt, ob\nein Software-Update verfügbar ist.", el_GR="Η διαδικασία διακόπηκε. Ελέγξτε αργότερα, αν υπάρχει διαθέσιμη αναβάθμιση\nλογισμικού.", en_GB="The procedure has been cancelled. Please check again later if a software update\nis available.", es_ES="El proceso se ha cancelado. Por favor, compruebe más tarde si hay una\nactualización de software.", fi_FI="Toiminto keskeytyi. Tarkista myöhemmin, onko ohjelmistopäivitys saatavilla.", fr_FR="La procédure a été annulée. Veuillez vérifier ultérieurement si une mise à jour\nlogicielle est disponible.", hr_HR="Postupak je prekinut. Provjerite kasnije je li raspoloživ update softvera.", hu_HU="A folyamat megszakadt. Ellenőrizd később, hogy elérhető-e szoftverfrissítés.", it_IT="L'operazione è stata interrotta. Si prega di verificare più tardi se è disponibile\nun update del software.", nl_NL="Het proces werd afgebroken. Controleer op een later moment of er een\nsoftware-update beschikbaar is.", no_NO="Prosessen er avbrutt. Kontroller om en programvareoppdatering er tilgjengelig\npå et senere tidspunkt.", pl_PL="Proces zosrał anulowany. Sprawdź ponownie później, czy jest dostępna\naktualizacja oprogramowania.", pt_PT="O procedimento foi interrompido. Por favor, verifica mais tarde se está\ndisponível uma atualização de software.", ro_RO="Procesul a fost întrerupt. Verificaţi ulterior, dacă este disponibilă o actualizare\nsoftware.", ru_RU="Процесс был прерван. Пожалуйста, проверьте позднее, доступно ли\nобновление программного обеспечения.", sk_SK="Proces bol prerušený. Prosím, neskôr skontrolujte, či je k dispozícii aktualizácia\nsoftvéru.", sl_SI="Postopek je bil prekinjen. Pozneje preverite, ali je na voljo posodobitev\nprogramske opreme.", sr_RS="Postupak je prekinut. Proverite kasnije da li je dostupno ažuriranje softvera.", sv_SE="Processen avbröts. Kontrollera vid en senare tidpunkt om en\nprogramvaruuppdatering är tillgänglig.", tr_TR="İşlem iptal edildi. Lütfen daha sonra bir yazılım güncellemesi olup olmadığını\nkontrol et.", uk_UA="Процес було скасовано. Будь ласка, перевірте пізніше, чи буде доступне\nоновлення програмного забезпечення.")
texttool_globals_dialog_message___popup_error_fatal_1_pannenruf = TextObject(bs_BA="Aktualizacija softvera je izvršena uz grešku. Vozilo je spremno za vožnju, ali se mora\nračunati na ograničenja funkcija. Stupite u kontakt s Vašim Audi partnerom.\nPogledajte priručnik", cs_CZ="Aktualizace softwaru byla provedena nesprávně. Vozidlo je schopné jízdy, ale je\ntřeba počítat s omezením funkcí. Obraťte se na svého partnera Audi. Viz palubní\nkniha", da_DK="Softwareopdateringen blev gennemført med fejl. Bilen er køreklar,\nmen funktionsbegrænsninger må påregnes. Kontakt din Audi partner.\nSe instruktionsbog.", de_DE="Das Software-Update wurde fehlerhaft durchgeführt. Das Fahrzeug ist fahrbereit,\njedoch ist mit Funktionseinschränkungen zu rechnen. Bitte kontaktiere deinen Audi\nPartner. Siehe Bordbuch", el_GR="Η αναβάθμιση λογισμικού εκτελέστηκε εσφαλμένα. Το όχημα είναι έτοιμο προς\nκίνηση, ωστόσο, θα πρέπει να αναμένονται περιορισμοί λειτουργίας. Επικοινωνήστε\nμε τον εξουσιοδοτημένο συνεργάτη Audi που σας εξυπηρετεί. Δείτε βιβλίο οδηγιών", en_GB="The software update was not performed correctly. The vehicle can be driven, but\nfunctional restrictions are to be expected. Please contact your Audi dealer. See\nowner's manual", es_ES="El software no se ha actualizado correctamente. El vehículo está en disposición para\ncircular, pero algunas funciones están limitadas. Por favor, consulte a su\nConcesionario Audi. Ver Manual", fi_FI="Ohjelmistopäivitys on suoritettu virheellisesti. Autolla voi ajaa, mutta toiminnoissa\nsaattaa olla rajoitteita. Ota yhteyttä Audi-jälleenmyyjään. Ks. käyttöohjekirja.", fr_FR="La mise à jour logicielle n'a pas été réalisée correctement. Le véhicule est en état de\ncirculer, mais des restrictions fonctionnelles sont à prévoir. Veuillez contacter votre\nPartenaire Audi. Voir Notice d'Utilisation", hr_HR="Update softvera nije proveden na pravilan način. Vozilo je pripravno za vožnju ali\ntreba računati s funkcijskim ograničenjima. Kontaktirajte sa svojim Audi partnerom.\nVidi priručnu literaturu", hu_HU="A szoftverfrissítés végrehajtása hibákkal történt. A jármű vezethető, de\nműködéskorlátozásokkal kell számolni. Vedd fel a kapcsolatot Audi partnereddel.\nLásd a fedélzeti irodalmat", it_IT="L'update del software è stato eseguito in modo errato. È possibile guidare la\nvettura, ma con alcune limitazioni funzionali. Contattare il partner Audi.\nVedi libretto", nl_NL="De software-update is onjuist uitgevoerd. Het voertuig is rijklaar, maar er zijn\nfunctiebeperkingen te verwachten. Neem contact op met je Audi Partner. Zie\ninstructieboekje", no_NO="Programvareoppdateringen ble utført feil. Du kan kjøre bilen, men noen funksjoner\nkan være begrenset. Kontakt Audi-verkstedet. Se instruksjonsboken", pl_PL="Aktualizacja oprogramowania została wykonana nieprawidłowo. Samochód jest\nzdatny do jazdy, ale należy się liczyć z ograniczeniami funkcji. Proszę skontaktować\nsię z dealerem Audi. Patrz instrukcja obsługi", pt_PT="A atualização do software foi incorretamente realizada. O veículo está pronto a\ncircular, no entanto poderão existir restrições de funcionamento. Por favor,\ncontacta o teu Concessionário Audi. Ver Manual de Bordo", ro_RO="Actualizarea software a fost realizată cu erori. Autovehiculul poate fi condus, dar\ntrebuie luate în calcul limitări funcţionale. Contactaţi partenerul Audi. Consultaţi\nmapa de bord", ru_RU="Обновление программного обеспечения было выполнено некорректно.\nАвтомобиль готов к эксплуатации, но следует ожидать функциональных\nограничений. Обратитесь к вашему партнеру Audi. См. руководство по\nэксплуатации", sk_SK="Aktualizácia softvéru sa vykonala nesprávne. Vozidlo je pripravené na jazdu, avšak\ntreba počítať s funkčnými obmedzeniami. Prosím, kontaktujte svojho partnera Audi.\nPozrite palubnú dokumentáciu", sl_SI="Napaka pri posodobitvi programske opreme. Vozilo je vozno, vendar so funkcije\nlahko omejene. Obrnite se na pooblaščenega partnerja Audi. Glejte Navodila", sr_RS="Ažuriranje softvera je izvršeno sa greškama. Vozilo je spremno za vožnju, ali treba\nračunati na ograničenja funkcija. Stupite u kontakt sa vašim Audi partnerom.\nVideti priručnu literaturu", sv_SE="Programvaruuppdateringen genomfördes felaktigt. Bilen kan köras, men räkna\nmed funktionsbegränsningar. Kontakta din Audi-partner. Se instruktionsboken", tr_TR="Yazılım güncellemesi hatalı şekilde uygulandı. Araç sürüşe hazırdır ancak\nfonksiyonel kısıtlamaların olması beklenebilir. Lütfen Audi yetkili servisine başvur.\nKullanım kılavuzuna bakın", uk_UA="Оновлення програмного забезпечення було виконано некоректно. Окремі\nфункції автомобіля недоступні, але автомобіль готовий до руху. Будь ласка,\nзв'яжіться з вашим партнером Audi. Див. бортову документацію")
texttool_globals_dialog_message___popup_error_fatal_1_pannenruf_new_version = TextObject(bs_BA="Aktualizacija softvera je izvršena uz grešku. Vozilo je spremno za vožnju, ali se mora računati na ograničenja funkcija. Stupite u kontakt s Vašim Audi partnerom. Pogledajte priručnik", cs_CZ="Aktualizace softwaru byla provedena nesprávně. Vozidlo je schopné jízdy, ale je třeba počítat s omezením funkcí. Obraťte se na svého partnera Audi. Viz palubní kniha", da_DK="Softwareopdateringen blev gennemført med fejl. Bilen er køreklar, men funktionsbegrænsninger må påregnes. Kontakt din Audi partner. Se instruktionsbog.", de_DE="Das Software-Update wurde fehlerhaft durchgeführt. Das Fahrzeug ist fahrbereit,\njedoch ist mit Funktionseinschränkungen zu rechnen. Bitte kontaktiere deinen Audi\nPartner. Siehe Bordbuch", el_GR="Η αναβάθμιση λογισμικού εκτελέστηκε εσφαλμένα. Το όχημα είναι έτοιμο προς\nκίνηση, ωστόσο, θα πρέπει να αναμένονται περιορισμοί λειτουργίας. Επικοινωνήστε\nμε τον εξουσιοδοτημένο συνεργάτη Audi που σας εξυπηρετεί. Δείτε βιβλίο οδηγιών", en_GB="The software update was not performed correctly. The vehicle can be driven, but functional restrictions are to be expected. Please contact your Audi dealer. See owner's manual", es_ES="El software no se ha actualizado correctamente. El vehículo está en disposición para circular, pero algunas funciones están limitadas. Por favor, consulte a su Concesionario Audi. Ver Manual", fi_FI="Ohjelmistopäivitys on suoritettu virheellisesti. Autolla voi ajaa, mutta toiminnoissa saattaa olla rajoitteita. Ota yhteyttä Audi-jälleenmyyjään. Ks. käyttöohjekirja.", fr_FR="La mise à jour logicielle n'a pas été réalisée correctement. Le véhicule est en état de circuler, mais des restrictions fonctionnelles sont à prévoir. Veuillez contacter votre Partenaire Audi. Voir Notice d'Utilisation", hr_HR="Update softvera nije proveden na pravilan način. Vozilo je pripravno za vožnju ali treba računati s funkcijskim ograničenjima. Kontaktirajte sa svojim Audi partnerom. Vidi priručnu literaturu", hu_HU="A szoftverfrissítés végrehajtása hibákkal történt. A jármű vezethető, de működéskorlátozásokkal kell számolni. Vedd fel a kapcsolatot Audi partnereddel. Lásd a fedélzeti irodalmat", it_IT="L'update del software è stato eseguito in modo errato. È possibile guidare la vettura, ma con alcune limitazioni funzionali. Contattare il partner Audi. Vedi libretto", nl_NL="De software-update is onjuist uitgevoerd. Het voertuig is rijklaar, maar er zijn functiebeperkingen te verwachten. Neem contact op met je Audi Partner. Zie instructieboekje", no_NO="Programvareoppdateringen ble utført feil. Du kan kjøre bilen, men noen funksjoner kan være begrenset. Kontakt Audi-verkstedet. Se instruksjonsboken", pl_PL="Aktualizacja oprogramowania została wykonana nieprawidłowo. Samochód jest zdatny do jazdy, ale należy się liczyć z ograniczeniami funkcji. Proszę skontaktować się z dealerem Audi. Patrz instrukcja obsługi", pt_PT="A atualização do software foi incorretamente realizada. O veículo está pronto a circular, no entanto poderão existir restrições de funcionamento. Por favor, contacta o teu Concessionário Audi. Ver Manual de Bordo", ro_RO="Actualizarea software a fost realizată cu erori. Autovehiculul poate fi condus, dar trebuie luate în calcul limitări funcţionale. Contactaţi partenerul Audi. Consultaţi mapa de bord", ru_RU="Обновление программного обеспечения было выполнено некорректно. Автомобиль готов к эксплуатации, но следует ожидать функциональных ограничений. Обратитесь к вашему партнеру Audi. См. руководство по эксплуатации", sk_SK="Aktualizácia softvéru sa vykonala nesprávne. Vozidlo je pripravené na jazdu, avšak treba počítať s funkčnými obmedzeniami. Prosím, kontaktujte svojho partnera Audi. Pozrite palubnú dokumentáciu", sl_SI="Napaka pri posodobitvi programske opreme. Vozilo je vozno, vendar so funkcije lahko omejene. Obrnite se na pooblaščenega partnerja Audi. Glejte Navodila", sr_RS="Ažuriranje softvera je izvršeno sa greškama. Vozilo je spremno za vožnju, ali treba računati na ograničenja funkcija. Stupite u kontakt sa vašim Audi partnerom. Videti priručnu literaturu", sv_SE="Programvaruuppdateringen genomfördes felaktigt. Bilen kan köras, men räkna med funktionsbegränsningar. Kontakta din Audi-partner. Se instruktionsboken", tr_TR="Yazılım güncellemesi hatalı şekilde uygulandı. Araç sürüşe hazırdır ancak fonksiyonel kısıtlamaların olması beklenebilir. Lütfen Audi yetkili servisine başvur. Kullanım kılavuzuna bakın", uk_UA="Оновлення програмного забезпечення було виконано некоректно. Окремі функції автомобіля недоступні, але автомобіль готовий до руху. Будь ласка, зв'яжіться з вашим партнером Audi. Див. бортову документацію")
texttool_globals_dialog_message___popup_error_fatal_2_pannenruf = TextObject(bs_BA="Smetnja! Nemojte koristiti vozilo - Vozilo nije spremno za vožnju! Aktualizacija\nsoftvera je izvršena uz grešku.\nStupite u kontakt s Vašim Audi partnerom.\nPogledajte priručnik", cs_CZ="Porucha! Nepoužívejte vozidlo – Vozidlo není připraveno k jízdě!\nAktualizace softwaru nebyla provedena správně.\nObraťte se na svého partnera Audi.\nViz palubní kniha", da_DK="Fejl! Anvend ikke bil - bil er ikke køreklar! Softwareopdateringen blev gennemført\nmed fejl. Kontakt din Audi partner. Se instruktionsbog.", de_DE="Störung! Benutze das Fahrzeug nicht - Das Fahrzeug ist nicht fahrbereit!\nDas Software-Update wurde fehlerhaft durchgeführt.\nBitte kontaktiere deinen Audi Partner.\nSiehe Bordbuch", el_GR="Βλάβη! Μην χρησιμοποιείτε το όχημα – Το όχημα δεν είναι έτοιμο προς κίνηση! Η\nαναβάθμιση λογισμικού εκτελέστηκε εσφαλμένα. Επικοινωνήστε με τον\nεξουσιοδοτημένο συνεργάτη Audi που σας εξυπηρετεί. Δείτε βιβλίο οδηγιών", en_GB="Error! Do not use the vehicle. The vehicle cannot be driven. The software update was\nnot performed correctly. Please contact your Audi dealer. See owner's manual", es_ES="¡Anomalía! No utilice el vehículo. ¡El vehículo no está en disposición para circular! El\nsoftware no se ha actualizado correctamente. Por favor, consulte a su Concesionario\nAudi. Ver Manual", fi_FI="Häiriö! Älä käytä autoa - sillä ei voi ajaa! Ohjelmistopäivitys on suoritettu\nvirheellisesti. Ota yhteyttä Audi-jälleenmyyjään. Ks. käyttöohjekirja.", fr_FR="Dysfonctionnement! N'utilisez pas le véhicule - Il n'est pas en état de circuler! La\nmise à jour logicielle n'a pas été réalisée correctement. Veuillez contacter votre\nPartenaire Audi. Voir Notice d'Utilisation", hr_HR="Smetnja! Nemojte koristiti vozilo. Vozilo nije pripravno za vožnju. Update softvera\nnije proveden na pravilan način. Kontaktirajte sa svojim Audi partnerom. Vidi\npriručnu literaturu", hu_HU="Üzemzavar! A járművet nem szabad használni. - A jármű nem vezethető!\nA szoftverfrissítés végrehajtása hibákkal történt. Vedd fel a kapcsolatot Audi\npartnereddel.\nLásd a fedélzeti irodalmat", it_IT="Anomalia! Non utilizzare la vettura - la vettura non è predisposta per la marcia!\nL'update del software è stato eseguito in modo errato. Contattare il partner Audi.\nVedi libretto", nl_NL="Storing! Gebruik het voertuig niet - Het voertuig is niet rijklaar!\nDe software-update is onjuist uitgevoerd.\nNeem contact op met je Audi Partner.\nZie instructieboekje", no_NO="Feil! Ikke bruk bilen. Bilen kan ikke kjøres!\nProgramvareoppdateringen ble utført feil.\nKontakt Audi-verkstedet.\nSe instruksjonsboken", pl_PL="Usterka! Nie korzystaj z pojazdu - pojazd jest niezdatny do jazdy!\nAktualizacja oprogramowania została wykonana nieprawidłowo. Proszę\nskontaktować się z dealerem Audi.\nPatrz instrukcja obsługi", pt_PT="Falha! Não utilizes o veículo. O veículo não está pronto a circular! A atualização do\nsoftware foi incorretamente realizada. Por favor, contacta o teu Concessionário\nAudi. Ver Manual de Bordo", ro_RO="Defecţiune! Nu utilizaţi autovehiculul - autovehiculul nu poate fi condus!\nActualizarea software a fost realizată cu erori.\nContactaţi partenerul Audi.\nConsultaţi mapa de bord", ru_RU="Неисправность! Не используйте автомобиль. Автомобиль не готов к движению!\nОбновление программного обеспечения было выполнено некорректно.\nПожалуйста, свяжитесь с вашим партнером Audi. См. руководство по\nэксплуатации", sk_SK="Porucha! Vozidlo nepoužívajte – vozidlo nie je pojazdné!\nAktualizácia softvéru sa vykonala nesprávne.\nProsím, kontaktujte svojho partnera Audi.\nPozrite palubnú dokumentáciu", sl_SI="Motnja! Ne uporabljajte vozila – vozilo ni vozno!\nNapaka pri posodobitvi programske opreme.\nObrnite se na pooblaščenega partnerja Audi.\nGlejte Navodila", sr_RS="Smetnja! Nemojte koristiti vozilo - vozilo nije spremno za vožnju! Ažuriranje\nsoftvera je izvršeno sa greškama. Stupite u kontakt sa vašim Audi partnerom.\nVideti priručnu literaturu", sv_SE="Systemfel! Använd inte bilen – bilen kan inte köras! Programvaruuppdateringen\ngenomfördes felaktigt. Kontakta din Audi-partner. Se instruktionsboken", tr_TR="Arıza! Aracı kullanma. - Araç sürüşe hazır değildir! Yazılım güncellemesi hatalı\nşekilde uygulandı. Lütfen Audi yetkili servisine başvur. Kullanım kılavuzuna bakın", uk_UA="Несправність! Не використовуйте автомобіль. Автомобіль не готовий до руху!\nОновлення програмного забезпечення було виконано некоректно. Будь ласка,\nзв'яжіться з вашим партнером Audi. Див. бортову документацію")
