update_available_installation_error_fatal_text = TextObject(bs_BA="Nemojte koristiti vozilo! Stupite u kontakt sa Vašim Audi partnerom. Pogledajte priručnik", cs_CZ="Vozidlo nepoužívejte! Obraťte se prosím na svého partnera Audi. Viz palubní kniha", da_DK="Anvend ikke bil! Kontakt din Audi partner. Se instruktionsbog.", de_DE="Fahrzeug nicht benutzen! Bitte kontaktiere deinen Audi Partner. Siehe Bordbuch", el_GR="Μην χρησιμοποιείτε το όχημα! Απευθυνθείτε στον εξουσιοδοτημένο Συνεργάτη Audi που σας εξυπηρετεί.\nΔείτε βιβλίο οδηγιών", en_GB="Do not use vehicle! Please contact your Audi dealer. See owner's manual", es_ES="¡No utilice el vehículo! Por favor, contacte con su Concesionario Audi. Ver Manual", fi_FI="Älä käytä autoa! Ota yhteyttä Audi-jälleenmyyjään. Ks. käyttöohjekirja.", fr_FR="N'utilisez pas le véhicule! Veuillez contacter votre Partenaire Audi. Voir Notice d'Utilisation", hr_HR="Nemojte koristiti vozio. Kontaktirajte sa svojim Audi partnerom. Vidi priručnu literaturu", hu_HU="Nem szabad használni a járművet. Kérünk, vedd fel a kapcsolatot Audi partnereddel. Lásd a fedélzeti irodalmat", it_IT="Non utilizzare la vettura! Contattare il partner Audi. Vedi libretto", nl_NL="Voertuig niet gebruiken! Neem contact op met je Audi Partner. Zie instructieboekje", no_NO="Ikke bruk bilen! Kontakt din Audi-forhandler. Se instruksjonsboken", pl_PL="Nie korzystaj z pojazdu! Proszę skontaktować się z dealerem Audi. Patrz instrukcja obsługi", pt_PT="Não utilizar o veículo! Por favor, contacta o teu Concessionário Audi. Ver Manual de Bordo", ro_RO="Nu utilizaţi autovehiculul! Contactaţi partenerul Audi. Consultaţi mapa de bord", ru_RU="Не используйте автомобиль! Свяжитесь с вашим партнером Audi. См. руководство по эксплуатации", sk_SK="Vozidlo nepoužívajte! Prosím, kontaktujte svojho partnera Audi. Pozrite palubnú dokumentáciu", sl_SI="Ne uporabljajte vozila! Obrnite se na pooblaščenega partnerja Audi. Glejte Navodila", sr_RS="Nemojte koristiti vozilo! Stupite u kontakt sa vašim Audi partnerom. Videti priručnu literaturu", sv_SE="Använd inte fordonet. Kontakta din Audi-partner. Se instruktionsboken", tr_TR="Aracı kullanma! Lütfen Audi Yetkili Servisine başvur. Kullanım kılavuzuna bakın", uk_UA="Не використовуйте автомобіль! Будь ласка, зв'яжіться з вашим партнером Audi. Див. посібник з експлуатації")
update_available_installation_error_fatal_text_mqb = TextObject(bs_BA="Aktualizacija softvera: Smetnja! Nemojte koristiti vozilo. Stupite u kontakt s Vašim Audi partnerom. Pogledajte priručnik", cs_CZ="Aktualizace softwaru: Porucha! Nepoužívejte vozidlo. Kontaktujte svého partnera Audi. Viz palubní kniha", da_DK="Softwareopdatering: Fejl! Anvend ikke bil. Kontakt din Audi partner. Se instruktionsbog.", de_DE="Software-Update: Störung! Benutze das Fahrzeug nicht. Bitte kontaktiere deinen Audi Partner. Siehe Bordbuch", el_GR="Αναβάθ. λογισμ.: Βλάβη! Μην χρησιμ. το όχημα. Επικοινωνήστε με τον εξουσ. συνεργ. Audi π.σας εξυπηρ. Δείτε βιβλ. οδηγ.", en_GB="Software update: fault. Do not use the vehicle. Please contact your Audi dealer. See owner's manual", es_ES="Actualización de software: ¡Anomalía! No utilice el vehículo. Por favor, contacte con su Concesionario Audi. Ver Manual", fi_FI="Ohjelmistopäivitys: häiriö! Älä käytä autoa. Ota yhteyttä Audi-jälleenmyyjään. Ks. käyttöohjekirja.", fr_FR="Mise à jour logicielle: dysfonctionnement. N'utilisez pas le véhicule! Veuillez contacter votre Partenaire Audi. Voir Notice", hr_HR="Update softvera: smetnja! Kontaktirajte sa svojim Audi partnerom. Vidi priručnu literaturu", hu_HU="Szoftverfrissítés: üzemzavar! Ne használd a jm.vet. Vedd fel a kapcsolatot Audi partnereddel. Lásd a fedélzeti irodalmat", it_IT="Update del software: anomalia! Non utilizzare la vettura. Contattare il partner Audi. Vedi libretto", nl_NL="Software-update: storing! Gebruik het voertuig niet. Neem contact op met je Audi Partner. Zie instructieboekje", no_NO="Programvareoppdatering: Feil! Ikke bruk bilen! Kontakt Audi-verkstedet. Se instruksjonsboken", pl_PL="Aktualizacja oprogramowania: usterka! Nie korzystaj z samochodu. Skontaktuj się z dealerem Audi. Patrz instrukcja", pt_PT="Atualização do software: falha! Não utilizes o veículo. Por favor, contacta o teu Concessionário Audi. Ver Manual de Bordo", ro_RO="Actualizare software: defecţiune! Nu utilizaţi autovehiculul! Contactaţi partenerul Audi. Consultaţi mapa de bord", ru_RU="Обновление ПО: неисправность! Не используйте а/м. Свяжитесь с вашим партнером Audi. См. рук-во по экспл.", sk_SK="Aktualizácia softvéru: Porucha! Nepoužívajte vozidlo. Kontaktujte svojho partnera Audi. Pozrite palubnú dokumentáciu", sl_SI="Posodobitev progr. opreme: motnja! Ne uporabljajte vozila. Obrnite se na pooblaščenega partnerja Audi. Glejte Navodila", sr_RS="Ažuriranje softvera: Smetnja! Nemojte koristiti vozilo. Stupite u kontakt s Audi partnerom. Videti priručnu literaturu", sv_SE="Programvaruuppdatering: Systemfel! Använd inte bilen. Kontakta din Audi-partner. Se instruktionsboken", tr_TR="Yazılım güncellemesi: Arıza! Aracı kullanma. Lütfen Audi yetkili servisine başvur. Kullanım kılavuzuna bakın", uk_UA="Оновлення ПЗ: несправність! Не використовуйте автомобіль. Зверніться до вашого партнера Audi. Див. борт. докум.")
update_available_installation_error_major_text = TextObject(bs_BA="Moguć ograničen nastavak vožnje", cs_CZ="Možnost omezeného pokračování v jízdě", da_DK="Kørsel fortsat mulig i begrænset omfang", de_DE="Eingeschränkte Weiterfahrt möglich", el_GR="Περιορισμένη δυνατότητα συνέχισης της πορείας", en_GB="You can continue driving with restrictions", es_ES="Se puede seguir conduciendo con limitaciones", fi_FI="Matkan jatkaminen rajoitetusti mahdollista.", fr_FR="Vous pouvez continuer à rouler avec des restrictions", hr_HR="Moguć ograničen nastavak vožnje", hu_HU="Korlátozott továbbhaladás lehetséges", it_IT="È possibile proseguire la marcia con alcune limitazioni", nl_NL="Beperkt verder rijden mogelijk", no_NO="Du kan kjøre videre med begrensninger", pl_PL="Możliwa dalsza jazda z ograniczeniami", pt_PT="Possível prosseguir viagem com restrições", ro_RO="Continuarea deplasării posibilă limitat", ru_RU="Возможно ограниченное движение", sk_SK="Pokračovanie v jazde možné s obmedzením", sl_SI="Vožnjo lahko nadaljujete v omejem obsegu", sr_RS="Moguć ograničen nastavak vožnje", sv_SE="Möjligt att köra vidare med begränsningar", tr_TR="Kısıtlı olarak sürüşe devam edilebilir", uk_UA="Можливе обмежене продовження руху")
update_available_installation_error_minor_text = TextObject(bs_BA="Stanje vozila nepromijenjeno. Moguć nastavak vožnje. Stupite u kontakt s Audi partnerom za sprovođenje aktualizacije.", cs_CZ="Stav vozidla je nezměněn. Je možné pokračovat v jízdě. Kontaktujte svého part. Audi, aby provedl akt. soft.", da_DK="Bilstatus uændret. Kørsel fortsat mulig. Kontakt din Audi partner for at få gennemført softwareopdateringen.", de_DE="Fahrzeugzustand unverändert. Weiterfahrt möglich. Audi Partner kontaktieren, um das Update durchführen zu lassen.", el_GR="Η κατ.τ.οχήμ.δεν έχ.αλλ. Συνέχ.πορ.εφικτή. Επικ.με τ.εξουσ.Συνεργ.Audi π.σας εξυπηρ., γ.να αναθέσ.τ.εκτέλ.τ.αναβ.λογισμ.", en_GB="Vehicle state unchanged. You can continue driving. Contact your Audi dealer to have the software update performed.", es_ES="Sin cambios en el vehículo. Puede seguir conduciendo. Contacte con su Concesionario Audi para actualizar el software.", fi_FI="Auton tila on ennallaan. Ajamista voi jatkaa. Ota yhteyttä Audi-jälleenmyyjään ohjelmiston päivittämistä varten.", fr_FR="État du véhicule inchangé. Conduite possible. Contactez votre Partenaire Audi pour faire réaliser la mise à jour logicielle.", hr_HR="Stanje vozila nepromijenjeno. Moguć nastavak vožnje. Kontaktirajte s Audi partnerom radi updatea softvera.", hu_HU="Jm.állapot nem változott. A továbbhaladás lehetséges. A frissítés érdekében vedd fel a kapcsolatot Audi partnereddel.", it_IT="Stato della vettura invariato. È possibile proseguire la marcia. Contattare il partner Audi per far eseguire l'update.", nl_NL="Voertuigtoestand ongewijzigd. Verder rijden mogelijk. Neem contact op met Audi Partner om update te laten uitvoeren.", no_NO="Bilens status er uendret. Du kan kjøre videre. Kontakt Audi-forhandleren for å få oppdatert programvaren.", pl_PL="Stan pojazdu bez zmian. Możliwa dalsza jazda. W celu aktualizacji oprogramowania skontaktuj się z dealerem Audi.", pt_PT="Estado do veíc. inalterado. Possível prosseguir viagem. Contactar Conc. Audi para realizar a atualização.", ro_RO="Stare autoveh. nemodificată. Continuare deplasare posibilă. Contactaţi partenerul Audi, pentru executarea actualizării.", ru_RU="Состояние а/м не изменилось. Возможно движение. Для обновления обратитесь к партнеру Audi.", sk_SK="Stav vozidla je nezmenený. Pokračovanie v jazde možné. Kontaktujte partnera Audi, aby mohol vykonať aktualizáciu.", sl_SI="Stanje vozila je nespremenjeno. Vožnjo lahko nadaljujete. Za posodobitev se obrnite na pooblaščenega partnerja Audi.", sr_RS="Stanje vozila neizmenjeno. Moguć nastavak vožnje. Stupite u kontakt s Audi partnerom za ažuriranje softvera.", sv_SE="Bilens status oförändrad. Möjligt att köra vidare. Kontakta din Audi-partner för att genomföra uppdateringen.", tr_TR="Araç durumu değişmedi. Sürüşe devam edilebilir. Güncellemenin uygulanması için, Audi yetkili servisine başvur.", uk_UA="Стан а/м не змінився. Можливий рух. Для оновлення програмного забезпечення зверніться до партнера Audi.")
update_available_installation_pending = TextObject(bs_BA="Aktualizacija softvera predstoji", cs_CZ="Aktualizace softwaru čeká", da_DK="Softwareopdatering afventer", de_DE="Software-Update ausstehend", el_GR="Αναβάθμιση λογισμικού εκκρεμεί", en_GB="Software update outstanding", es_ES="Actualización de software pendiente", fi_FI="Ohjelmistopäivitys odottaa", fr_FR="Mise à jour logicielle en attente", hr_HR="Očekuje se update softvera", hu_HU="Szoftverfrissítés függőben", it_IT="Update del software in attesa", nl_NL="Software-update in afwachting", no_NO="Programvareoppdatering mangler", pl_PL="Aktualizacja oprogramowania: oczekująca", pt_PT="Atualização do software pendente", ro_RO="Actualizare software în aşteptare", ru_RU="Ожидается обновление программного обеспечения", sk_SK="Chýbajúca aktualizácia softvéru", sl_SI="Posodobitev programske opreme v teku", sr_RS="Predstoji ažuriranje softvera", sv_SE="Väntande programvaruuppdatering", tr_TR="Yazılım güncellemesi beklemede", uk_UA="Очікується оновлення програмного забезпечення")
update_available_installation_remaining_duration_mqb = TextObject(bs_BA="Preostalo trajanje: %1", cs_CZ="Zbývající trvání: %1", da_DK="Resterende varighed: %1", de_DE="Restdauer: %1", el_GR="Υπολειπόμενη διάρκεια: %1", en_GB="Time remaining: %1", es_ES="Duración restante: %1", fi_FI="Jäljellä oleva aika: %1", fr_FR="Durée restante: %1", hr_HR="Preostalo vrijeme: %1", hu_HU="Hátralévő időtartam: %1", it_IT="Durata residua: %1", nl_NL="Resterende duur: %1", no_NO="Gjenværende tid: %1", pl_PL="Pozostały czas: %1", pt_PT="Duração restante: %1", ro_RO="Durată rămasă: %1", ru_RU="Оставшаяся продолжительность: %1", sk_SK="Zostávajúca doba: %1", sl_SI="Preostali čas trajanja: %1", sr_RS="Preostalo trajanje: %1", sv_SE="Återstående tid: %1", tr_TR="Kalan süre: %1", uk_UA="Залишкова тривалість: %1")
update_available_installation_waiting_for_preconditions = TextObject(bs_BA="Uvjerite se da su ispunjeni svi uslovi prije nego izađete. Aktualizacija počinje nakon napuštanja i zaključavanja\nvozila.", cs_CZ="Než vystoupíte, zkontrolujte prosím, že jsou všechny podmínky splněné. Update se spustí po opuštění a zamčení\nvozidla.", da_DK="Sørg for, at alle betingelser er opfyldt, før du stiger ud. Opdateringen starter, efter at du har forladt og låst\nbilen.", de_DE="Bitte stelle sicher, dass alle Bedingungen erfüllt sind, bevor du aussteigst. Das Update startet nach Verlassen und\nVerriegeln des Fahrzeugs.", el_GR="Πριν αποβιβαστ., εκπληρώστε όλες τ. συνθήκες. Η αναβάθμ. ξεκινά μετά την αποβίβαση/το κλείδωμα.", en_GB="Please ensure that all the conditions are met before you get out of the vehicle. The update will start after you have\nleft the vehicle and locked it.", es_ES="Por favor, antes de salir del vehículo asegúrese de que se cumplen todos los requisitos. La actualización se inicia\ntras abandonar y bloquear el vehículo.", fi_FI="Varmista, että kaikki edellytykset ovat täyttyneet ennen kuin poistut autosta. Päivitys käynnistyy, kun olet\npoistunut autosta ja lukinnut sen.", fr_FR="Veuillez vous assurer que toutes les conditions sont remplies avant de quitter le véhicule. La mise à jour se lance\nune fois que vous avez quitté et verrouillé le véhicule.", hr_HR="Provjerite jesu li ispunjeni svi preduvjeti prije nego što napustite vozilo. Update počinje nakon napuštanja i\nzaključavanja vozila.", hu_HU="Kérünk, mielőtt kiszállsz a járműből, győződj meg arról, hogy minden feltétel teljesült-e. A frissítés a jármű\nelhagyása és bezárása után indul el.", it_IT="Accertarsi che tutte le condizioni siano soddisfatte prima di scendere dalla vettura. L'update si avvierà dopo aver\nlasciato e bloccato la vettura.", nl_NL="Voldoe aan alle voorwaarden voordat je uitstapt. Update start na verlaten/vergrendelen.", no_NO="Kontroller at alle betingelser er oppfylt, før du går ut av bilen. Oppdateringen starter etter at du har gått ut av\nbilen og låst den.", pl_PL="Zanim wysiądziesz, upewnij się, że wszystkie warunki są spełnione. Aktualizacja uruchomi się automatycznie po\nopuszczeniu i zamknięciu pojazdu.", pt_PT="Por favor, certifica-te que estão cumpridas todas as condições antes de saires. A atualização começa após saires e\ntrancares o veículo.", ro_RO="Asiguraţi-vă că sunt îndeplinite toate condiţiile, înainte de a coborî. Actualizarea porneşte după ce coborâţi şi\nîncuiaţi autovehiculul.", ru_RU="Перед выходом из автомобиля убедитесь, что все условия соблюдены. Обновление начинается после\nвыхода из автомобиля и блокировки.", sk_SK="Skôr ako vystúpite sa uistite, že sú splnené všetky podmienky. Aktualizácia sa spustí po opustení a uzamknutí\nvozidla.", sl_SI="Preden izstopite, preverite, da so izpolnjeni vsi pogoji. Posodobitev se zažene, ko zapustite in zaklenete vozilo.", sr_RS="Uverite se da su svi uslovi ispunjeni pre nego što izađete. Ažuriranje se pokreće nakon napuštanja i zaključavanja\nvozila.", sv_SE="Säkerställ att alla villkor är uppfyllda innan du stiger ur. Uppdateringen startar när du har lämnat och låst\nbilen.", tr_TR="Lütfen araçtan inmeden önce tüm koşulların yerine getirildiğinden emin ol. Güncelleme, aracı terk ettikten ve\naraç kilitlendikten sonra başlar.", uk_UA="Перед виходом з автомобіля переконайтеся, що всіх умов дотримано. Оновлення починається після виходу з\nавтомобіля та блокування.")
update_available_installation_waiting_for_preconditions_mqb = TextObject(bs_BA="Postarajte se da svi uslovi budu ispunjeni. Aktualizacija softvera se pokreće automatski.", cs_CZ="Ujistěte se prosím, že jsou splněny všechny podmínky. Akt. soft. se spustí automaticky.", da_DK="Sørg for, at alle betingelser er opfyldt. Softwareopdateringen starter automatisk.", de_DE="Bitte stelle sicher, dass alle Bedingungen erfüllt sind. Das Software-Update startet automatisch.", el_GR="Σιγουρευτείτε ότι εκπληρώνονται όλες οι προϋποθέσεις. Η αναβάθμιση λογισμικού θα ξεκινήσει αυτομάτως.", en_GB="Please ensure all conditions are met. The software update will start automatically.", es_ES="Asegúrese de que se cumplen todas las condiciones. El software se actualizará automáticamente.", fi_FI="Varmista, että kaikki edellytykset ovat täyttyneet. Ohjelmistopäivitys käynnistyy automaattisesti.", fr_FR="Veuillez vous assurer que toutes les conditions sont remplies. Mise à jour lancée automatiquement.", hr_HR="Provjerite jesu li ispunjeni svi preduvjeti. Update softvera počinje automatski.", hu_HU="Győződj meg arról, hogy minden feltétel teljesült-e. A szoftverfrissítés automatikusan elindul.", it_IT="Accertarsi che tutte le condizioni siano soddisfatte. L'update del software si avvierà automaticamente.", nl_NL="Zorg ervoor dat aan alle voorwaarden is voldaan. De software-update start automatisch.", no_NO="Sørg for at alle betingelsene er oppfylt. Programvareoppdateringen starter automatisk.", pl_PL="Upewnij się, że wszystkie warunki są spełnone. Aktualizacja oprogramowania rozpocznie się automatycznie.", pt_PT="Certifica-te que todas as condições estão cumpridas. A atualização do software começa automaticamente.", ro_RO="Asiguraţi-vă că sunt îndeplinite toate condiţiile. Actualizarea software porneşte automat.", ru_RU="Убедитесь, что все условия выполнены. Обновление программного обеспечения запустится автоматически.", sk_SK="Prosím, uistite sa, že sú splnené všetky podmienky. Aktualizácia softvéru sa spustí automaticky.", sl_SI="Preverite, da so izpolnjeni vsi pogoji. Posodobitev programske opreme se zažene avtomatsko.", sr_RS="Uverite se da su ispunjeni svi uslovi. Ažuriranje softvera počinje automatski.", sv_SE="Kontrollera att alla villkor är uppfyllda. Programvaruuppdateringen startar automatiskt.", tr_TR="Lütfen, tüm koşulların yerine getirildiğinden emin ol. Yazılım güncellemesi otomatik olarak başlar.", uk_UA="Переконайтеся, що всі умови виконані. Оновлення програмного забезпечення розпочнеться автоматично.")
update_available_may_be_installed_later = TextObject(bs_BA="Možete instalirati aktualizaciju prilikom sljedećeg isključivanja vozila.", cs_CZ="Update můžete instalovat při příštím odstavení vozidla.", da_DK="Du kan installere opdatering efter næste parkering af bil.", de_DE="Du kannst das Update beim nächsten Abstellen des Fahrzeugs installieren.", el_GR="Μπορείτε να εγκαταστήσετε την αναβάθμιση κατά την επόμενη στάθμευση του οχήματος.", en_GB="You can install the update the next time the vehicle is parked.", es_ES="Puede instalar la actualización la próxima vez que estacione el vehículo.", fi_FI="Voit asentaa päivityksen, kun auto seuraavan kerran pysäköidään.", fr_FR="Vous pourrez installer la mise à jour la prochaine fois que le véhicule sera stationné.", hr_HR="Možete instalirati update kod sljedećeg zaustavljanja vozila.", hu_HU="A jármű következő leállításakor telepítheted a frissítést.", it_IT="È possibile installare l'update alla prossima sosta della vettura.", nl_NL="Je kunt de update installeren de volgende keer dat je je voertuig neerzet.", no_NO="Du kan installere oppdateringen neste gang du parkerer bilen.", pl_PL="Aktualizację możesz zainstalować przy najbliższym zaparkowaniu pojazdu.", pt_PT="Podes instalar a atualização aquando da próxima paragem do veículo.", ro_RO="Puteţi instala actualizarea la următoarea parcare a autovehiculului.", ru_RU="Вы можете установить обновление при следующей стоянке автомобиля.", sk_SK="Aktualizáciu môžete nainštalovať pri nasledujúcom odstavení vozidla.", sl_SI="Posodobitev lahko namestite pri naslednji zaustavitvi vozila.", sr_RS="Ažuriranje možete instalirati prilikom sledećeg isključivanja vozila.", sv_SE="Du kan installera uppdateringen nästa gång du stannar fordonet.", tr_TR="Güncellemeyi, araç bir sonraki park edildiğinde yükleyebilirsin.", uk_UA="Ви можете встановити оновлення під час наступної стоянки автомобіля.")
update_available_may_be_installed_later_mqb = TextObject(bs_BA="Aktualizacija se može instalirati prilikom sljedećeg zaustavljanja vozila kada je vozilo isključeno.", cs_CZ="Aktualizaci lze nainstalovat při příštím zaparkování vozidla s vypnutým motorem.", da_DK="Opdateringen kan installeres efter næste parkering af bilen, når den er slukket.", de_DE="Das Update kann beim nächsten Abstellen des Fahrzeugs bei ausgeschaltetem Fahrzeug installiert werden.", el_GR="Η αναβάθμιση μπορεί να εγκατασταθ.στην επόμενη στάθμευση, ενώ το όχημα είναι απενεργοποιημένο.", en_GB="The update can be installed the next time the vehicle is parked and switched off.", es_ES="La actualización se puede instalar con el vehículo apagado la próxima vez que estacione el vehículo.", fi_FI="Päivitys voidaan asentaa, kun auto seuraavan kerran pysäköidään ja auto on kytketty pois päältä.", fr_FR="La mise à jour pourra être installée la prochaine fois que le véhicule sera immobilisé et l'alim. coupée.", hr_HR="Update se može instalirati kod sljedećeg parkiranja dok je vozilo isključeno.", hu_HU="A frissítés a jármű következő leállításakor, kikapcsolt járműnél telepíthető.", it_IT="È possibile installare l'update alla prossima sosta della vettura, con la vettura spenta.", nl_NL="De update kan worden geïnstalleerd wanneer je de volgende keer parkeert als het voertuig uit is.", no_NO="Oppdateringen kan installeres neste gang du parkerer og slår av bilen.", pl_PL="Aktualizację można zainstalować po następnym zaparkowaniu i wyłączeniu pojazdu.", pt_PT="A atualização pode ser instalada quando o veículo voltar a ser parado e desligado.", ro_RO="Actualizarea poate fi instalată la următoarea parcare a autovehiculului, cu autovehiculul dezactivat.", ru_RU="Обновление может быть установлено при следующей стоянке автомобиля с выключенным двигателем.", sk_SK="Aktualizáciu je možné nainštalovať pri ďalšom odstavení a vypnutí vozidla.", sl_SI="Posodobitev je pri izključenem vozilu mogoče namestiti pri naslednjem izklopu vozila.", sr_RS="Ažuriranje može da se instalira prilikom sledećeg zaustavljanja vozila dok je vozilo isključeno.", sv_SE="Uppdateringen kan installeras nästa gång bilen är avstängd.", tr_TR="Güncelleme, araç bir sonraki park edildiğinde araç kapalıyken yüklenebilir.", uk_UA="Оновлення може бути встановлено під час наступної стоянки автомобіля з вимкненим двигуном.")
update_available_no_updates = TextObject(bs_BA="Vaš sistem je na najnovijoj verziji.", cs_CZ="Systém je na nejnovějším stavu.", da_DK="Dit system har den nyeste version.", de_DE="Dein System ist auf dem neuesten Stand.", el_GR="Το σύστημά σας αντιστοιχεί στη νεότερη έκδοση.", en_GB="Your system is up to date.", es_ES="El sistema está actualizado.", fi_FI="Järjestelmä on ajan tasalla.", fr_FR="Votre système est à jour.", hr_HR="Sustav je po najnovijem stanju.", hu_HU="Rendszered a legfrisssebb állapotban van.", it_IT="Il sistema è aggiornato.", nl_NL="Je systeem werkt in de nieuwste versie.", no_NO="Systemet er oppdatert.", pl_PL="System jest w najnowszej wersji.", pt_PT="O sistema encontra-se na versão mais atual.", ro_RO="Sistemul dumneavoastră este la zi.", ru_RU="Ваша система обновлена.", sk_SK="Váš systém je na najnovšej úrovni.", sl_SI="Vaš sistem je posodobljen.", sr_RS="Vaš sistem je na najnovijoj verziji.", sv_SE="Ditt system är uppdaterat till senaste versionen.", tr_TR="Sistemin güncel durumda.", uk_UA="Вашу систему оновлено.")
update_available_no_updates_privacy_on = TextObject(bs_BA="Zbog Vaših postavki za zaštitu podataka aktualizacija softvera Vam nije raspoloživa. Za\nkorištenje ove usluge aktivirajte mobilne podatke.", cs_CZ="Vzhledem k vašemu nastavení ochrany osobních údajů není aktualizace softwaru dostupná.\nChcete-li používat tuto službu, aktivujte si mobilní data.", da_DK="På grund af dine databeskyttelsesindstillinger er softwareopdateringen ikke til rådighed for\ndig. Aktiver mobildata for at kunne anvende denne tjeneste.", de_DE="Aufgrund deiner Datenschutzeinstellungen steht dir das Software-Update nicht zur\nVerfügung. Um diesen Dienst nutzen zu können, aktiviere bitte die mobilen Daten.", el_GR="Εξαιτίας των ρυθμίσεών προστασίας δεδομένων σας, δεν είναι στη διάθεσή σας η αναβάθμιση\nλογισμικού. Ενεργοποιήστε τα δεδομένα κινητής τηλεφωνίας, για να μπορέσετε να\nχρησιμοποιήσετε αυτή την υπηρεσία.", en_GB="The software update is not available due to your privacy settings. Please activate mobile data\nto use this service.", es_ES="El software no se puede actualizar por sus ajustes de privacidad. Para poder utilizar este\nservicio, active los datos móviles.", fi_FI="Tietosuoja-asetusten vuoksi ohjelmistopäivitys ei ole käytettävissä. Aktivoi mobiilidata\nkäyttääksesi tätä palvelua.", fr_FR="Vous ne pouvez pas activer la mise à jour logicielle en raison de vos réglages de la\nconfidentialité. Veuillez activer les données mobiles pour pouvoir utiliser ce service.", hr_HR="Uslijed vaših postavki zaštite podataka update softvera nije raspoloživ. Kako biste koristili tu\nuslugu, aktivirajte mobilne podatke.", hu_HU="Adatvédelmi beállításaid miatt a szoftverfrissítés nem áll a rendelkezésedre. Ennek a\nszolgáltatásnak a használatához aktiváld a mobil adatokat.", it_IT="A causa delle impostazioni per la protezione dati, l'update del software non è disponibile. Per\npoter utilizzare questo servizio, attivare i dati mobili.", nl_NL="Vanwege je privacy-instellingen is de software-update niet mogelijk voor jou. Om de dienst te\nkunnen gebruiken, moet je de mobiele gegevens activeren.", no_NO="På grunn av personverninnstillingene har du ikke tilgang til programvareoppdateringen. Du\nmå aktivere mobildata for å kunne bruke denne tjenesten.", pl_PL="Ze względu na Twoje ustawienia prywatności, aktualizacja oprogramowania jest dla Ciebie\nniedostępna. Aby móc korzystać z tej usługi, proszę włączyć mobilne przesyłanie danych.", pt_PT="Devido aos teus ajustes da proteção de dados a atualização do software não está disponível.\nPara poderes utilizar este serviço, por favor, ativa os dados móveis.", ro_RO="Datorită setărilor de protecţie a datelor, nu vă stă la dispoziţie actualizarea software. Pentru\na putea utiliza acest serviciu, activaţi datele mobile.", ru_RU="Из-за настроек защиты данных обновление программного обеспечения недоступно. Чтобы\nвоспользоваться этим сервисом, включите мобильные данные.", sk_SK="Z dôvodu vašich nastavení ochrany údajov aktualizácia softvéru pre vás nie je k dispozícii. Aby\nste mohli využívať túto službu, aktivujte si mobilné dáta.", sl_SI="Zaradi vaših nastavitev zasebnosti posodobitev programske opreme ni na voljo. Za uporabo\nstoritve aktivirajte mobilne podatke.", sr_RS="Zbog vaših podešavanja za zaštitu podataka vam ažuriranje softvera nije dostupno. Da biste\nmogli koristiti ovu uslugu, aktivirajte mobilne podatke.", sv_SE="På grund av dina integritetsinställningar är programvaruuppdateringen inte tillgänglig.\nAktivera mobildata för att kunna använda tjänsten.", tr_TR="Gizlilik ayarların nedeniyle yazılım güncellemesi senin için mevcut değil. Bu hizmeti\nkullanabilmek için, lütfen mobil verileri etkinleştir.", uk_UA="У зв'язку з вашими налаштуваннями захисту даних, оновлення програмного\nзабезпечення недоступне. Щоб скористатися цією службою, активуйте мобільні дані.")
update_available_privacy_settings_button_text = TextObject(bs_BA="Postavke zaštite podataka", cs_CZ="Nastavení ochrany dat", da_DK="Databeskyttelses­indstillinger", de_DE="Datenschutzeinstellungen", el_GR="Ρυθμίσεις προστασίας προσωπικών δεδομένων", en_GB="Privacy settings", es_ES="Ajustes de privacidad", fi_FI="Tietosuoja-asetukset", fr_FR="Réglages de la confidentialité", hr_HR="Postavke zaštite podataka", hu_HU="Adatvédelmi beállítások", it_IT="Impostazioni per la protezione dati", nl_NL="Privacy­instellingen", no_NO="Personverninnstillinger", pl_PL="Ustawienia polityki prywatności", pt_PT="Ajustes da proteção de dados", ro_RO="Setări pentru protecţia datelor", ru_RU="Настройки защиты данных", sk_SK="Nastavenia ochrany údajov", sl_SI="Nastavitve zasebnosti", sr_RS="Podešavanja za zaštitu podataka", sv_SE="Sekretessinställningar", tr_TR="Gizlilik ayarları", uk_UA="Настройки захисту даних")
update_not_available_change_language = TextObject(bs_BA="Zbog promjene jezika se vrši ponovno preuzimanje napomena o verziji. Sačekajte...", cs_CZ="Vzhledem ke změně jazyka budou poznámky k vydání staženy znovu. Počkejte prosím…", da_DK="På grund af skift af sprog downloades versionsinformationerne igen. Vent...", de_DE="Aufgrund des Sprachwechsels werden die Versionshinweise erneut heruntergeladen. Bitte warten...", el_GR="Εξαιτίας της αλλαγής γλώσσας, θα γίνει εκ νέου λήψη των υποδείξεων έκδοσης. Παρακαλώ περιμένετε...", en_GB="Version information is being downloaded again due to the language being switched. Please wait...", es_ES="La información sobre la versión se descargará de nuevo porque se ha cambiado el idioma. Por favor, espere...", fi_FI="Versiotiedot ladataan uudelleen kielen vaihtamisen vuoksi. Odota...", fr_FR="Nouveau téléchargement des notes de version en raison du changement de langue. Veuillez patienter...", hr_HR="Zbog promjene jezika ponovno će se preuzeti napomene o verziji. Čekajte...", hu_HU="A nyelv megváltoztatása miatt a változatra vonatkozó információk újra letöltésre kerülnek. Kérlek, várj...", it_IT="A causa del cambio di lingua, verranno nuovamente scaricate le informazioni sulla versione. Attendere prego...", nl_NL="Vanwege de taalwijziging wordt de versie-informatie opnieuw gedownload. Even geduld...", no_NO="Versjonsinformasjonen lastes på nytt fordi du byttet språk. Vent litt...", pl_PL="Ze względu na zmianę języka, informacje o wersji będą pobrane ponownie. Proszę czekać...", pt_PT="Devido à mudança de idioma serão novamente descarregadas as informações da versão. Por favor, aguardar...", ro_RO="Datorită schimbării limbii se descarcă din nou indicaţiile referitoare la versiune. Vă rugăm aşteptaţi...", ru_RU="В связи с изменением языка информация о версии будет загружена заново. Пожалуйста, ждите...", sk_SK="Z dôvodu zmeny jazyka sa poznámky k verzii stiahnu znova. Čakajte, prosím...", sl_SI="Zaradi menjave jezika se opombe o različici prenašajo znova. Prosimo, počakajte ...", sr_RS="Napomene o verziji će biti ponovo preuzete zbog promene jezika. Molimo sačekajte...", sv_SE="På grund av bytet av språk laddas versionsinformationen ner på nytt. Vänligen vänta...", tr_TR="Dil değişikliği nedeniyle sürüm notları tekrar indirilecektir. Lütfen bekleyin...", uk_UA="У зв'язку зі зміною мови інформація про версію буде завантажена заново. Зачекайте...")
update_not_available_preparing = TextObject(bs_BA="Aktualizacija softvera u postupku pripreme", cs_CZ="Připravuje se aktualizace softwaru", da_DK="Softwareopdatering forberedes.", de_DE="Software-Update wird vorbereitet", el_GR="Γίνεται προετοιμασία της αναβάθμισης λογισμικού", en_GB="Preparing software update", es_ES="Preparando la actualización de software", fi_FI="Ohjelmistopäivitystä valmistellaan", fr_FR="Préparation de la mise à jour logicielle en cours...", hr_HR="Update softvera se priprema", hu_HU="Szoftverfrissítés előkészítése", it_IT="Update del software in fase di preparazione", nl_NL="Software-update wordt voorbereid", no_NO="Forbereder programvareoppdatering", pl_PL="Przygotowywanie aktualizacji oprogramowania", pt_PT="A preparar a atualização do software", ro_RO="Se pregăteşte actualizarea software", ru_RU="Готовится обновление программного обеспечения", sk_SK="Aktualizácia softvéru sa pripravuje", sl_SI="Posodobitev programske opreme je v pripravi", sr_RS="Ažuriranje softvera je u pripremi", sv_SE="Programvaruuppdateringen förbereds", tr_TR="Yazılım güncellemesi hazırlanıyor", uk_UA="Оновлення програмного забезпечення готується")
update_prerequisites_batteryLevelOk = TextObject(bs_BA="Baterija elektronike vozila nije dovoljno napunjena ili je temperatura okruženja suviše niska. Vozite kako biste\nnapunili bateriju ili pokušajte ponovo na većoj temperaturi okruženja.", cs_CZ="Palubní baterie není dostatečně nabitá nebo je okolní teplota příliš nízká. Jeďte baterii nabít nebo to zkuste znovu\npři vyšší okolní teplotě.", da_DK="Bilens batteri er ikke tilstrækkeligt opladet eller omgivelsestemperaturen er for lav. Kør for at lade batteriet op,\neller forsøg igen ved en højere omgivelsestemperatur.", de_DE="Die Bordnetzbatterie ist nicht ausreichend geladen oder die Umgebungstemperatur ist zu gering.\nBitte fahre, um die Batterie zu laden oder versuche es bei höherer Umgebungstemperatur erneut.", el_GR="Η μπαταρία τροφοδοσίας δικτύου δεν είναι φορτισμένη επαρκώς ή η θερμοκρασία περιβάλλοντος είναι πολύ\nχαμηλή. Κινήστε το όχημα για να φορτίσετε την μπαταρία ή προσπαθήστε πάλι σε υψηλότερτη θερμοκρασία\nπεριβάλλοντος.", en_GB="The onboard supply battery has not been charged sufficiently or the ambient temperature is too low.\nPlease drive to charge the battery or try again when the ambient temperature is higher.", es_ES="La batería de la red de a bordo no está suficientemente cargada o la temperatura ambiente es demasiado baja.\nConduzca para que la batería se cargue o inténtelo de nuevo cuando suba la temperatura ambiente.", fi_FI="Sähköverkon akku ei ole riittävästi latautunut tai ympäristön lämpötila on liian alhainen. Lataa akkua ajamalla tai\nyritä uudelleen, kun ympäristön lämpötila on noussut.", fr_FR="La batterie du réseau de bord n'est pas suffisamment chargée ou la température ambiante est trop faible. Veuillez\nrouler pour recharger la batterie ou essayez à nouveau lorsque la température ambiante sera plus élevée.", hr_HR="Akumulator strujne mreže nije dovoljno napunjen ili je okolna temperatura preniska. Vozite se s vozilom kako\nbiste napunili akumulator ili pokušate ponovno kada okolna temperatura bude viša.", hu_HU="Az elektromos rendszer akkumulátor nincs megfelelően feltöltve, vagy a környezeti hőmérséklet túl alacsony.\nKérünk, vezess az akkumulátor feltöltéséhez, vagy próbáld újra magasabb környezeti hőmérsékletnél.", it_IT="La batteria della rete di bordo non è sufficientemente carica o la temperatura ambiente è troppo bassa.\nGuidare per ricaricare la batteria o riprovare quando la temperatura ambiente sarà più alta.", nl_NL="De accu van de elektrische installatie is niet voldoende opgeladen of de omgevingstemperatuur is te laag. Rijd om\nde accu op te laden of probeer het opnieuw bij een hogere omgevingstemperatuur.", no_NO="Batteriet for bilens ledningsnett er ikke ladet nok, eller temperaturen i omgivelsene er for lav. Kjør for å lade\nbatteriet, eller prøv igjen når temperaturen i omgivelsene er høyere.", pl_PL="Akumulator rozruchowy nie jest wystarczająco naładowany lub temperatura otoczenia jest zbyt niska. Jedź\npojazdem, aby naładować akumulator lub spróbuj ponownie w wyższej temperaturze otoczenia.", pt_PT="A bateria da rede de bordo não está suficientemente carregada ou a temperatura ambiente é muito baixa.\nPor favor, circula para carregares a bateria ou volta a tentar com uma temperatura ambiente mais alta.", ro_RO="Bateria reţelei de bord nu este încărcată suficient sau temperatura ambiantă este prea mică. Conduceţi, pentru a\nîncărca bateria sau reîncercaţi la o temperatură ambiantă mai mare.", ru_RU="Аккумулятор бортовой сети недостаточно заряжен или температура окружающей среды слишком низкая.\nЗарядите аккумулятор или повторите попытку при более высокой температуре окружающей среды.", sk_SK="Akumulátor palubnej siete nie je dostatočne nabitý alebo je okolitá teplota príliš nízka. Prosím, jazdite, aby ste\nnabili akumulátor, alebo to skúste znova pri vyššej teplote okolia.", sl_SI="Omrežna baterija ni dovolj napolnjena ali pa je temperatura okolice prenizka. Vozite, da napolnite baterijo, ali\nposkusite znova pri višji temperaturi okolice.", sr_RS="Baterija elektronske instalacije nije dovoljno napunjena ili je temperatura okruženja suviše niska. Molimo vas da\nvozite da biste napunili bateriju ili pokušajte ponovo pri većim temperaturama okruženja.", sv_SE="Elsystemets batteri är inte tillräckligt laddat eller omgivningstemperaturen är för låg. Kör för att ladda batteriet\neller försök igen vid en högre omgivningstemperatur.", tr_TR="Merkezi elektrik aküsü yeterince şarj edilmemiş veya ortam sıcaklığı çok düşük. Lütfen aküyü şarj etmek için sürüş\nyap veya ortam sıcaklığı daha yüksek olduğunda tekrar dene.", uk_UA="Бортова акумуляторна батарея недостатньо заряджена або температура навколишнього середовища занадто\nнизька. Будь ласка, проїдьте, щоб зарядити акумулятор, або спробуйте ще раз при вищій температурі\nнавколишнього середовища.")
update_prerequisites_chargingInactive = TextObject(bs_BA="Postupak punjenja je aktivan. Završite postupak punjenja.", cs_CZ="Proces nabíjení je aktivní. Ukončete prosím proces nabíjení.", da_DK="Opladning aktiv. Afslut opladning.", de_DE="Der Ladevorgang ist aktiv. Bitte beende den Ladevorgang.", el_GR="Η διαδικασία φόρτισης είναι ενεργή. Τερματίστε τη διαδικασία φόρτισης.", en_GB="Charging active. Please stop the charging process.", es_ES="El proceso de carga está activo. Finalícelo.", fi_FI="Lataus on aktiivinen. Lopeta lataus.", fr_FR="La procédure de recharge est active. Veuillez interrompre la procédure de recharge.", hr_HR="Postupak punjenja je aktivan. Završite postupak punjenja.", hu_HU="A töltési folyamat aktív. Kérünk, fejezd be a töltési folyamatot.", it_IT="Il processo di ricarica è attivo. Si prega di terminarlo.", nl_NL="Het laadproces is actief. Beëindig het oplaadproces.", no_NO="Lading pågår. Avslutt ladingen.", pl_PL="Proces ładowania jest aktywny. Proszę zakończyć ładowanie.", pt_PT="O carregamento está ativo. Por favor, termina o carregamento.", ro_RO="Procesul de încărcare este activ. Opriţi procesul de încărcare.", ru_RU="Процесс зарядки активен. Завершите процесс зарядки.", sk_SK="Proces nabíjania je aktívny. Prosím, ukončite nabíjanie.", sl_SI="Polnjenje je aktivno. Zaključite polnjenje.", sr_RS="Postupak punjenja je aktivan. Molimo da završite postupak punjenja.", sv_SE="Laddningsprocessen är aktiv. Avsluta laddningsprocessen.", tr_TR="Şarj işlemi aktif. Lütfen şarj işlemini sonlandır.", uk_UA="Процес заряджання активний. Завершіть процес заряджання.")
